def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i, cap in enumerate(bins):
        if cap == 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.25:
            score += ((1 - ratio) ** 4) * 20
            for x in range(1, 6):
                if x % 2 == 1:
                    score += np.cos(ratio * x * np.pi) * 3
                else:
                    score -= np.sin(ratio * x * np.pi) * 1.5
            if cap > 10:
                for y in range(2, 7, 2):
                    if cap % y == 0:
                        score += y * 0.7
        elif 0.25 <= ratio < 0.5:
            score += np.sqrt(ratio) * 12
            odd_factors = [f for f in range(1, int(cap)+1) if cap % f == 0 and f % 2 == 1]
            for factor in odd_factors:
                if factor < item:
                    score += factor * 0.15
            for m in range(1, 5):
                score += ((-1) ** m) * np.log1p(ratio * m) * 2
        elif 0.5 <= ratio < 0.75:
            score += np.exp(-abs(0.6 - ratio) * 10) * 18
            for p in range(1, int(cap) + 1):
                if p % 3 == 0:
                    if cap % p == 0:
                        score += np.sqrt(p) * 1.1
            for q in range(1, 4):
                score += np.sin(ratio * q * np.e) * 2.5
        elif 0.75 <= ratio <= 1:
            score += np.tanh((ratio - 0.75) * 15) * 22
            for r in range(1, int(cap // 2) + 1):
                if cap % r == 0:
                    score += (r % 4) * 1.3
            prime_check = True
            for s in range(2, int(cap ** 0.5) + 1):
                if cap % s == 0:
                    prime_check = False
                    break
            if prime_check:
                score *= 1.2
        else:
            frac_part = ratio - int(ratio)
            int_ratio = int(ratio)
            penalty = 0
            for t in range(1, int_ratio + 2):
                if int_ratio % t == 0:
                    penalty += t * (1 + frac_part)
            penalty += np.log1p(frac_part * cap) * 5
            score = penalty + (ratio - 1) ** 2 * 30
            if ratio > 3:
                for u in range(1, int(cap // 3) + 1):
                    if cap % u == 0:
                        score += np.sin(u * np.pi / 7) * 2
        if cap % 4 == 0 and ratio < 1:
            score *= 1.05
        if ratio > 1.2 and cap % 6 == 0:
            score *= 0.85
        if cap > 15:
            score += np.log1p(cap) * 0.7
        priorities[i] = score
    min_p = np.nanmin(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_p + 250)
    return priorities
